package com.ayush.advanced; import org.junit.jupiter.params.ParameterizedTest; import org.junit.jupiter.params.provider.ValueSource; import static org.junit.jupiter.api.Assertions.*; class EvenCheckerTest { @ParameterizedTest @ValueSource(ints={2,4,10,100}) void returnsTrueForEvenNumbers(int n){ assertTrue(new EvenChecker().isEven(n)); } @ParameterizedTest @ValueSource(ints={1,3,9,101}) void returnsFalseForOddNumbers(int n){ assertFalse(new EvenChecker().isEven(n)); }}